  "title": "टोपोलॉजिकल सॉर्टिंग",
  "group": "ग्राफ़ एल्गोरिदम",
  "options": [
    {
      "text": "ग्राफ़ में चक्र (cycles) होने चाहिए"
    },
    {
      "text": "ग्राफ़ भारित (weighted) और जुड़ा हुआ (connected) होना चाहिए"
    },
    {
      "text": "ग्राफ़ अदिशात्मक (undirected) और चक्ररहित (acyclic) होना चाहिए"
    },
    {
      "text": "ग्राफ़ दिशात्मक (directed) और चक्ररहित (acyclic) होना चाहिए"
    }
  ],
  "questionProse": [
    "किसी ग्राफ़ पर टोपोलॉजिकल सॉर्टिंग लागू करने के लिए कौन सी शर्तें अनिवार्य हैं?"
  ],
  "explanationProse": [
    "टोपोलॉजिकल सॉर्टिंग केवल तभी संभव है जब ग्राफ़ दिशात्मक और चक्ररहित (DAG) हो। चक्रों की मौजूदगी किसी भी वैध रैखिक क्रम को असंभव बना देती है, इसलिए यह ऑर्डरिंग टास्क शेड्यूलिंग जैसी समस्याओं के लिए आदर्श है जहाँ कार्यों के बीच स्पष्ट निर्भरताएँ होती हैं।"
  ]
}
